-	}
-	for _, entry := range entries {
-		if !entry.IsDir() {
-			continue
-		}
-		doltDir := filepath.Join(basePath, entry.Name(), ".dolt")
-		if info, err := os.Stat(doltDir); err == nil && info.IsDir() {
-			return true
-		}
-	}
-	return false
-}

